73	/// Load and validate Gallops from a file
74	///
75	/// Performs these steps in order:
76	/// 1. Deserialize JSON to Gallops struct
77	/// 2. Round-trip validation: reserialize and compare bytes (validates stored format)
78	/// 3. Semantic validation via jjrg_validate
79	///
80	/// Returns ValidatedGallops wrapper that guarantees the data has passed all checks.
81	pub fn jjdr_load(path: &Path) -> Result<jjdr_ValidatedGallops, String> {
82	    // Read original bytes
83	    let original_bytes = fs::read(path)
84	        .map_err(|e| format!("Failed to read file '{}': {}", path.display(), e))?;
85	
86	    let mut gallops: jjrg_Gallops = serde_json::from_slice(&original_bytes)
87	        .map_err(|e| format!("Failed to parse JSON: {}", e))?;
88	
89	    // Detect old-format files: heat_order absent or schema_version absent.
90	    // Old-format files cannot pass round-trip check because BTreeMap serializes heats
91	    // in sorted key order, which differs from original furlough-shuffled order.
92	    //
93	    // Also detect stale next_pensum_seed field (removed in v3.7 — pensum seeds moved
94	    // to officium-local storage). Serde silently ignores the unknown field on read,
95	    // but re-serialization omits it, causing round-trip byte mismatch until the next
96	    // save writes the clean format back to disk.
97	    const PENSUM_SEED_KEY: &[u8] = b"\"next_pensum_seed\"";
98	    let needs_pensum_seed_removal = !gallops.heats.is_empty()
99	        && original_bytes.windows(PENSUM_SEED_KEY.len()).any(|w| w == PENSUM_SEED_KEY);
100	    let is_migration_mode = gallops.heat_order.is_empty()
101	        || gallops.schema_version.is_none()
102	        || needs_pensum_seed_removal;
103	
104	    if !is_migration_mode {
105	        let reserialized = serde_json::to_string_pretty(&gallops)
106	            .map_err(|e| format!("Failed to reserialize JSON: {}", e))?;
107	
108	        if reserialized.as_bytes() != original_bytes {
109	            let diff_pos = zjjdr_find_first_diff(&original_bytes, reserialized.as_bytes());
110	            return Err(format!("Round-trip validation failed at byte {}", diff_pos));
111	        }
112	    }
113	
114	    // Populate missing fields on first load of old-format file.
115	    // BTreeMap guarantees sorted key order for heat_order.
116	    if is_migration_mode {
117	        if gallops.heat_order.is_empty() {
118	            gallops.heat_order = gallops.heats.keys().cloned().collect();
119	        }
120	        gallops.schema_version = Some(4);
121	    }
122	
123	    // Semantic validation
124	    jjrg_validate(&gallops)
125	        .map_err(|errors| format!("Validation failed: {}", errors.join("; ")))?;
126	
127	    Ok(jjdr_ValidatedGallops(gallops))
128	}
129	
130	/// Save Gallops to a file with validation
131	///
132	/// Performs atomic write with validation:
133	/// 1. Serialize to JSON
134	/// 2. Write to temp file
135	/// 3. Validate temp file via jjdr_load
136	/// 4. Rename temp to target (atomic)
137	///
138	/// If validation fails, temp file is deleted and error returned.
139	pub fn jjdr_save(gallops: &jjrg_Gallops, path: &Path) -> Result<(), String> {
140	    // Serialize to pretty JSON
141	    let json = serde_json::to_string_pretty(gallops)
142	        .map_err(|e| format!("Failed to serialize JSON: {}", e))?;
143	
144	    // Create temp file in same directory for atomic rename
145	    let parent = path.parent().ok_or_else(|| "Invalid path: no parent directory".to_string())?;
146	    let temp_path = parent.join(format!(".tmp.{}.json", std::process::id()));
147	
148	    // Write to temp file
149	    fs::write(&temp_path, &json)
150	        .map_err(|e| format!("Failed to write temp file: {}", e))?;
151	
152	    // Validate what we wrote by loading it back
153	    match jjdr_load(&temp_path) {
154	        Ok(_) => {
155	            // Validation passed, rename to target
156	            fs::rename(&temp_path, path)
157	                .map_err(|e| format!("Failed to rename temp file to target: {}", e))?;
158	            Ok(())
159	        }
160	        Err(e) => {
161	            // Validation failed, clean up temp file
162	            let _ = fs::remove_file(&temp_path);
163	            Err(format!("Save validation failed: {}", e))
164	        }
165	    }
166	}
