168	/// Save Gallops and commit with paddock in a single operation
169	///
170	/// This is the standard routine for JJK operations that modify gallops.
171	/// It saves the gallops file, then commits both the gallops and the paddock file
172	/// for the given heat using machine_commit.
173	///
174	/// Returns the commit hash on success.
175	pub fn jjri_persist(
176	    lock: &vvc::vvcc_CommitLock,
177	    gallops: &jjrg_Gallops,
178	    file: &Path,
179	    firemark: &crate::jjrf_favor::jjrf_Firemark,
180	    message: String,
181	    size_limit: u64,
182	    output: &mut vvc::vvco_Output,
183	) -> Result<String, String> {
184	    // Save gallops first
185	    jjdr_save(gallops, file)?;
186	
187	    // Construct paths for commit
188	    let gallops_path = file.to_string_lossy().to_string();
189	    let paddock_path = jjri_paddock_path(firemark.jjrf_as_str());
190	
191	    // Commit using machine_commit with explicit file list
192	    let commit_args = vvc::vvcm_CommitArgs {
193	        files: vec![
194	            gallops_path,
195	            paddock_path,
196	        ],
197	        message,
198	        size_limit,
199	        warn_limit: 30000,
200	    };
201	
202	    vvc::machine_commit(lock, &commit_args, output)
203	}
