87	/// Two-level map gazette with freeze-on-disclosure semantics
88	#[derive(Debug)]
89	pub struct jjrz_Gazette {
90	    vocabulary: Vec<jjrz_Slug>,
91	    notices: BTreeMap<jjrz_Slug, BTreeMap<String, String>>,
92	    frozen: Cell<bool>,
93	}
94	
95	impl jjrz_Gazette {
96	    /// Construct a frozen gazette from raw markdown per the wire format.
97	    ///
98	    /// All validation errors are collected and returned as a diagnostic list
99	    /// rather than failing on the first.
100	    pub fn jjrz_parse(vocabulary: &[jjrz_Slug], markdown: &str) -> Result<jjrz_Gazette, Vec<String>> {
101	        let mut diagnostics: Vec<String> = Vec::new();
102	        let mut notices: BTreeMap<jjrz_Slug, BTreeMap<String, String>> = BTreeMap::new();
103	        let vocab_set: std::collections::HashSet<jjrz_Slug> = vocabulary.iter().copied().collect();
104	
105	        // (slug, lede, content_lines, header_line_number)
106	        let mut current: Option<(jjrz_Slug, String, Vec<String>, usize)> = None;
107	        let mut in_fence = false;
108	
109	        for (line_idx, line) in markdown.lines().enumerate() {
110	            let line_num = line_idx + 1;
111	
112	            if line.starts_with("```") {
113	                in_fence = !in_fence;
114	            }
115	
116	            if !in_fence && zjjrz_is_notice_boundary(line) {
117	                if let Some((slug, lede, content_lines, hdr_line)) = current.take() {
118	                    zjjrz_finalize_notice(slug, &lede, &content_lines, hdr_line, &mut notices, &mut diagnostics);
119	                }
120	
121	                let after_hash = line[1..].trim();
122	                if after_hash.is_empty() {
123	                    diagnostics.push(format!("Line {}: malformed header (no slug after #)", line_num));
124	                    continue;
125	                }
126	
127	                let (slug_str, lede) = match after_hash.split_once(char::is_whitespace) {
128	                    Some((s, l)) => (s, l.trim().to_string()),
129	                    None => (after_hash, String::new()),
130	                };
131	
132	                match jjrz_Slug::jjrz_from_str(slug_str) {
133	                    Some(slug) if vocab_set.contains(&slug) => {
134	                        current = Some((slug, lede, Vec::new(), line_num));
135	                    }
136	                    Some(slug) => {
137	                        diagnostics.push(format!(
138	                            "Line {}: slug '{}' not in vocabulary (accepted: {})",
139	                            line_num, slug, zjjrz_format_vocab(vocabulary)
140	                        ));
141	                    }
142	                    None => {
143	                        diagnostics.push(format!(
144	                            "Line {}: unknown slug '{}' (valid: {})",
145	                            line_num, slug_str, zjjrz_format_vocab(vocabulary)
146	                        ));
147	                    }
148	                }
149	            } else if let Some((_, _, ref mut content_lines, _)) = current {
150	                content_lines.push(line.to_string());
151	            }
152	        }
153	
154	        if let Some((slug, lede, content_lines, hdr_line)) = current.take() {
155	            zjjrz_finalize_notice(slug, &lede, &content_lines, hdr_line, &mut notices, &mut diagnostics);
156	        }
157	
158	        if diagnostics.is_empty() {
159	            Ok(jjrz_Gazette {
160	                vocabulary: vocabulary.to_vec(),
161	                notices,
162	                frozen: Cell::new(true),
163	            })
164	        } else {
165	            Err(diagnostics)
166	        }
167	    }
168	
169	    /// Construct an unfrozen, empty gazette
170	    pub fn jjrz_build(vocabulary: &[jjrz_Slug]) -> jjrz_Gazette {
171	        jjrz_Gazette {
172	            vocabulary: vocabulary.to_vec(),
173	            notices: BTreeMap::new(),
174	            frozen: Cell::new(false),
175	        }
176	    }
