261	
262	/// Parse gazette input for enroll (slate) operation.
263	/// Returns (silks, docket) from a single slate notice.
264	/// Validates: exactly one slate notice, non-empty lede (silks).
265	pub fn jjrz_parse_slate_input(markdown: &str) -> Result<(String, String), String> {
266	    let g = jjrz_Gazette::jjrz_parse(&[jjrz_Slug::Slate], markdown)
267	        .map_err(|diags| diags.join("\n"))?;
268	    let entries = g.jjrz_query_by_slug(jjrz_Slug::Slate);
269	    if entries.is_empty() {
270	        return Err("No slate notice found in gazette input".to_string());
271	    }
272	    if entries.len() > 1 {
273	        return Err(format!("Expected one slate notice, got {}", entries.len()));
274	    }
275	    let (silks, docket) = entries.into_iter().next().unwrap();
276	    if silks.is_empty() {
277	        return Err("Slate notice missing lede (silks)".to_string());
278	    }
279	    Ok((silks, docket))
