300	/// Parse gazette input for paddock setter operation.
301	/// Returns (firemark, content) from a single paddock notice.
302	/// Validates: exactly one paddock notice, non-empty lede (firemark).
303	pub fn jjrz_parse_paddock_input(markdown: &str) -> Result<(String, String), String> {
304	    let g = jjrz_Gazette::jjrz_parse(&[jjrz_Slug::Paddock], markdown)
305	        .map_err(|diags| diags.join("\n"))?;
306	    let entries = g.jjrz_query_by_slug(jjrz_Slug::Paddock);
307	    if entries.is_empty() {
308	        return Err("No paddock notice found in gazette input".to_string());
309	    }
310	    if entries.len() > 1 {
311	        return Err(format!("Expected one paddock notice, got {}", entries.len()));
312	    }
313	    let (firemark, content) = entries.into_iter().next().unwrap();
314	    if firemark.is_empty() {
315	        return Err("Paddock notice missing lede (firemark)".to_string());
316	    }
317	    Ok((firemark, content))
318	}
