322	/// Build gazette output for read operations (orient, parade detail, paddock getter).
323	/// Returns emitted gazette markdown with paddock and optional pace notices.
324	/// Paddock lede is the firemark; pace ledes are coronets.
325	pub fn jjrz_build_read_output(firemark: &str, paddock_content: &str, paces: &[(&str, &str)]) -> String {
326	    let mut gazette = jjrz_Gazette::jjrz_build(&[jjrz_Slug::Paddock, jjrz_Slug::Pace]);
327	    gazette.jjrz_add(jjrz_Slug::Paddock, firemark, paddock_content).unwrap();
