106	    /// Resolve Pace — shared read primitive
107	    ///
108	    /// Navigate Gallops from a coronet to the target pace and its current tack state.
109	    /// Returns PaceContext with parsed identities and current state snapshot.
110	    pub fn jjrg_resolve_pace(&self, coronet: &str) -> Result<jjrg_PaceContext, String> {
111	        use crate::jjrf_favor::jjrf_Coronet as Coronet;
112	
113	        let parsed = Coronet::jjrf_parse(coronet)
114	            .map_err(|e| format!("Invalid coronet: {}", e))?;
115	        let coronet_key = parsed.jjrf_display();
116	        let firemark = parsed.jjrf_parent_firemark();
117	        let firemark_key = firemark.jjrf_display();
118	
119	        let heat = self.heats.get(&firemark_key)
120	            .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
121	        let pace = heat.paces.get(&coronet_key)
122	            .ok_or_else(|| format!("Pace '{}' not found", coronet_key))?;
123	        let current = pace.tacks.first()
124	            .ok_or_else(|| "Pace has no tacks (should never happen)".to_string())?;
125	
126	        Ok(jjrg_PaceContext {
127	            coronet_key,
128	            firemark_key,
129	            state: current.state.clone(),
130	            text: current.text.clone(),
131	            silks: current.silks.clone(),
132	            direction: current.direction.clone(),
133	        })
134	    }
135	
136	    /// Prepend Tack — shared write primitive
137	    ///
138	    /// Insert a new tack at position zero of a pace's tack history.
139	    /// Takes a PaceContext (from resolve_pace) so the coronet is parsed exactly once.
140	    pub fn jjrg_prepend_tack(&mut self, ctx: &jjrg_PaceContext, tack: jjrg_Tack) -> Result<(), String> {
141	        let heat = self.heats.get_mut(&ctx.firemark_key)
142	            .ok_or_else(|| format!("Heat '{}' not found", ctx.firemark_key))?;
143	        let pace = heat.paces.get_mut(&ctx.coronet_key)
144	            .ok_or_else(|| format!("Pace '{}' not found", ctx.coronet_key))?;
145	
146	        pace.tacks.insert(0, tack);
147	        Ok(())
148	    }
149	
150	    /// Revise Docket — composed method
151	    ///
152	    /// Pure state transform: resolve_pace → update docket → prepend_tack.
153	    /// Takes basis and ts from caller (procedure layer captures I/O).
154	    /// Returns PaceContext so calling procedure has firemark/silks for commit message.
155	    pub fn jjrg_revise_docket(&mut self, coronet: &str, docket: &str, basis: &str, ts: &str) -> Result<jjrg_PaceContext, String> {
156	        if docket.is_empty() {
157	            return Err("docket text must not be empty".to_string());
158	        }
159	
160	        let ctx = self.jjrg_resolve_pace(coronet)?;
161	
162	        let tack = jjrg_Tack {
163	            ts: ts.to_string(),
164	            state: ctx.state.clone(),
165	            text: docket.to_string(),
166	            silks: ctx.silks.clone(),
167	            basis: basis.to_string(),
168	            direction: None,
169	        };
170	
171	        self.jjrg_prepend_tack(&ctx, tack)?;
172	
173	        Ok(ctx)
174	    }
175	}
