344	/// Finalize a parsed notice: trim blank lines and insert into map
345	fn zjjrz_finalize_notice(
346	    slug: jjrz_Slug,
347	    lede: &str,
348	    content_lines: &[String],
349	    header_line: usize,
350	    notices: &mut BTreeMap<jjrz_Slug, BTreeMap<String, String>>,
351	    diagnostics: &mut Vec<String>,
352	) {
353	    let content = zjjrz_trim_blank_lines(content_lines);
354	    let inner = notices.entry(slug).or_default();
355	    if inner.contains_key(lede) {
356	        let lede_display = if lede.is_empty() { "<absent>" } else { lede };
357	        diagnostics.push(format!(
358	            "Line {}: duplicate key ({}, {:?})",
359	            header_line, slug, lede_display
360	        ));
361	    } else {
362	        inner.insert(lede.to_string(), content);
363	    }
364	}
