366	/// Trim leading and trailing blank lines, join remaining with newline
367	pub(crate) fn zjjrz_trim_blank_lines(lines: &[String]) -> String {
368	    let start = lines.iter().position(|l| !l.trim().is_empty()).unwrap_or(lines.len());
369	    let end = lines.iter().rposition(|l| !l.trim().is_empty()).map(|i| i + 1).unwrap_or(0);
370	    if start >= end {
371	        String::new()
372	    } else {
373	        lines[start..end].join("\n")
374	    }
375	}
