43	/// Capture current commit SHA for basis field
44	///
45	/// Runs `git rev-parse --short=N HEAD` where N is derived from JJRG_UNKNOWN_BASIS length.
46	/// Returns JJRG_UNKNOWN_BASIS on error (e.g., not in a git repo).
47	pub fn jjrg_capture_commit_sha() -> String {
48	    let short_arg = format!("--short={}", JJRG_UNKNOWN_BASIS.len());
49	    match vvc::vvce_git_command(&["rev-parse", &short_arg, "HEAD"])
50	        .output()
51	    {
52	        Ok(output) if output.status.success() => {
53	            String::from_utf8_lossy(&output.stdout).trim().to_string()
54	        }
55	        _ => JJRG_UNKNOWN_BASIS.to_string(),
56	    }
57	}
