59	/// Create a new Tack with current timestamp and basis SHA
60	///
61	/// Centralizes Tack creation to ensure consistent timestamp/basis capture.
62	/// All code creating new Tacks should use this helper.
63	///
64	/// Note: This captures ambient state (git HEAD, wall clock). The Operation
65	/// Taxonomy pattern (see JJS0) prefers pure construction with caller-provided
66	/// basis/ts — see jjrg_revise_docket for the exemplar. Existing callers will
67	/// migrate incrementally.
68	pub fn jjrg_make_tack(
69	    state: jjrg_PaceState,
70	    text: String,
71	    silks: String,
72	    direction: Option<String>,
73	) -> jjrg_Tack {
74	    jjrg_Tack {
75	        ts: timestamp_full(),
76	        state,
77	        text,
78	        silks,
79	        basis: jjrg_capture_commit_sha(),
80	        direction,
81	    }
82	}
