84	/// Read text from stdin (for CLI commands)
85	pub fn jjrg_read_stdin() -> Result<String, String> {
86	    let mut buffer = String::new();
87	    std::io::stdin().read_to_string(&mut buffer)
88	        .map_err(|e| format!("Failed to read from stdin: {}", e))?;
89	    Ok(buffer.trim_end().to_string())
90	}
91	
92	/// Read text from stdin, returning None if stdin is empty or a tty
93	pub fn jjrg_read_stdin_optional() -> Result<Option<String>, String> {
94	    use std::io::IsTerminal;
95	
96	    // If stdin is a terminal, no input was piped
97	    if std::io::stdin().is_terminal() {
98	        return Ok(None);
99	    }
100	
101	    let text = jjrg_read_stdin()?;
102	    if text.is_empty() {
103	        Ok(None)
104	    } else {
105	        Ok(Some(text))
106	    }
107	}
